`timescale 1ns / 1ps
 
module testbench_labtest_combinational;
    
    // ------------------ Specify variables generated by testbench ------------------ 
    reg in1, in2, in3;
    
    // ------------------ Specify variables that are watched by testbench ------------------ 
    wire out1, out2;
    
    // Instantiate hardware Device Under Test (dut)
    labtest_q1_hardware dut(.a(in1),.b(in2),.c(in3), .x(out1),.y(out2));
 
    // ------------------ Setup inputs ------------------
    // Provide initial values for inputs. The ‘initial’ command
    // is only valid within the testbench.
    // Can use this for all simple testbenches

    integer count;
    initial begin 
        count = 0;
    end
 
    always begin
        #50
        count=count+1;
    end
 
    // Toggle inputs at different rates to cover all input  
    always @(count) begin
        case (count)
            0 : begin {in1, in2, in3} = 3'b000; end
            1 : begin {in1, in2, in3} = 3'b001; end
            2 : begin {in1, in2, in3} = 3'b010; end
            3 : begin {in1, in2, in3} = 3'b011; end
            4 : begin {in1, in2, in3} = 3'b100; end
            5 : begin {in1, in2, in3} = 3'b101; end
            6 : begin {in1, in2, in3} = 3'b110; end
            7 : begin {in1, in2, in3} = 3'b111; end
            default : begin {in1, in2, in3} = count[2:0];end 
        endcase
    end

    // Dump VCD for GTKWave
    initial begin
        $dumpfile("testbench_labtest_combinational.vcd");
        $dumpvars(0, testbench_labtest_combinational);
        #1000 
        $finish;
	end
 
endmodule